org.machanism.macha.core.commons.configurator.Configurator conf = null;
org.machanism.machai.ai.manager.GenAIProvider provider = org.machanism.machai.ai.manager.GenAIProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
provider.instructions("You are a helpful assistant.");
provider.prompt("Hello!");
java.lang.String response = provider.perform();
provider.clear();

org.machanism.machai.ai.manager.GenAIProvider provider = null;
provider.addTool(
  "echo",
  "Returns the provided message.",
  (java.lang.Object[] args) -> {
    com.fasterxml.jackson.databind.JsonNode node = (com.fasterxml.jackson.databind.JsonNode) args[0];
    return node.has("message") ? node.get("message").asText() : "";
  },
  "message:string:required:Message to return"
);

