org.machanism.macha.core.commons.configurator.Configurator conf = null;
org.machanism.machai.ai.manager.GenAIProvider provider = org.machanism.machai.ai.manager.GenAIProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
org.machanism.machai.ai.tools.FunctionToolsLoader loader = org.machanism.machai.ai.tools.FunctionToolsLoader.getInstance();
loader.setConfiguration(conf);
loader.applyTools(provider);
provider.setWorkingDir(new java.io.File("/path/to/project"));

public final class MyTools implements org.machanism.machai.ai.tools.FunctionTools {
	@Override
	public void applyTools(org.machanism.machai.ai.manager.GenAIProvider provider) {
		provider.addTool(
			"my_tool",
			"Does something useful.",
			(java.lang.Object[] args) -> "ok",
			"param:string:optional:Example parameter"
		);
	}
}

public final class LoggingProvider extends org.machanism.machai.ai.manager.GenAIAdapter {
	@Override
	public void prompt(java.lang.String text) {
		org.slf4j.LoggerFactory.getLogger(getClass()).info("Prompt: {}", text);
		super.prompt(text);
	}
}

